// This swagger comment was generated by gemini
/**
 * @swagger
 * /api/schools:
 *   get:
 *     summary: Retrieve a list of driving schools
 *     tags: [Schools]
 *     security:
 *       - bearerAuth: []
 *     responses:
 *       200:
 *         description: A list of driving schools.
 *         content:
 *           application/json:
 *             schema:
 *               type: array
 *               items:
 *                 $ref: '#/components/schemas/DrivingSchool'
 */
schoolRouter.get("/", isAuthenticated, (req, res) => {
  try {
    const userId = (req as AuthRequest).payload?.user.UserId;
    const schools = schoolService.getAllSchools(userId);
    res.status(StatusCodes.OK).json(schools);
  } catch (error) {
    res
      .status(StatusCodes.INTERNAL_SERVER_ERROR)
      .json({ error: { message: (error as Error).message } });
  }
});

