/**
 * @swagger
 * /api/schools/{schoolId}:
 *   get:
 *     summary: Retrieve a single driving school
 *     tags: [Schools]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: path
 *         name: schoolId
 *         required: true
 *         schema:
 *           type: integer
 *         description: The ID of the school to retrieve
 *     responses:
 *       200:
 *         description: A single driving school.
 *         content:
 *           application/json:
 *             schema:
 *               $ref: '#/components/schemas/DrivingSchool'
 *       404:
 *         description: School not found
 *       400:
 *         description: Invalid schoolId
 */
schoolRouter.get("/:schoolId", isAuthenticated, (req, res) => {
  try {
    const id = parseInt(req.params.schoolId);
    const result = schoolService.getSchoolById(id);
    if (result.error) {
      res.status(result.status).json({ error: result.error });
    } else {
      res.status(result.status).json(result.data);
    }
  } catch (error) {
    res
      .status(StatusCodes.INTERNAL_SERVER_ERROR)
      .json({ error: { message: (error as Error).message } });
  }
});

schoolRouter.put("/:schoolId", isAuthenticated, (req, res) => {
  try {
    const id = parseInt(req.params.schoolId);
    const tokenUser = (req as AuthRequest).payload?.user as any;
    if (tokenUser?.DrivingSchoolId !== id && tokenUser?.Role !== "admin") {
      res.status(StatusCodes.FORBIDDEN).json({ error: { message: "Not authorized" } });
      return;
    }
    const { name, location, owner, email, website, phone, openingDays, openingTimeFrom, openingTimeTo } = req.body;
    if (!name) {
      res.status(StatusCodes.BAD_REQUEST).json({ error: { message: "Name is required" } });
      return;
    }
    const result = schoolService.updateSchool(id, name, location, owner, email, website, phone, openingDays, openingTimeFrom, openingTimeTo);
    if (result.error) {
      res.status(result.status).json({ error: result.error });
    } else {
      res.status(result.status).json({ data: { message: "School updated" } });
    }
  } catch (error) {
    res
      .status(StatusCodes.INTERNAL_SERVER_ERROR)
      .json({ error: { message: (error as Error).message } });
  }
});
